class Solution:
    def reverseKGroup(self, head, k):
        vals = []
        node = head
        while node:
            vals.append(node.val)
            node = node.next
        out = []
        for i in range(0, len(vals), k):
            block = vals[i:i + k]
            if len(block) == k:
                block = block[::-1]
            out.extend(block)
        new = None
        for v in reversed(out):
            new = ListNode(v, new)
        return new

